# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# App configuration
APP_TITLE = "Office Facial Recognition Security System"
TRAINING_DATA_DIR = "employee_photos"
MODEL_PATH = "models/face_model.pkl"
ENCODER_PATH = "models/label_encoder.pkl"
ENCODINGS_PATH = "models/face_encodings.pkl"

app = FastAPI(title=APP_TITLE, version="1.0.0")


class FaceRecognitionModel:
    """Facial recognition model that trains on employee photos and provides confidence scores."""

    def __init__(self):
        self.classifier: Optional[CalibratedClassifierCV] = None
        self.label_encoder: Optional[LabelEncoder] = None
        self.known_encodings: list = []
        self.known_labels: list = []
        self.is_trained: bool = False
        self._load_model()

    def _load_model(self):
        """Load pre-trained model if available."""
        try:
            if os.path.exists(MODEL_PATH) and os.path.exists(ENCODER_PATH) and os.path.exists(ENCODINGS_PATH):
                with open(MODEL_PATH, "rb") as f:
                    self.classifier = pickle.load(f)
                with open(ENCODER_PATH, "rb") as f:
                    self.label_encoder = pickle.load(f)
                with open(ENCODINGS_PATH, "rb") as f:
                    data = pickle.load(f)
                    self.known_encodings = data["encodings"]
                    self.known_labels = data["labels"]
                self.is_trained = True
                logger.info(f"Model loaded. Known employees: {list(self.label_encoder.classes_)}")
        except Exception as e:
            logger.warning(f"Could not load existing model: {e}")

    def _save_model(self):
        """Save trained model to disk."""
        os.makedirs("models", exist_ok=True)
        with open(MODEL_PATH, "wb") as f:
            pickle.dump(self.classifier, f)
        with open(ENCODER_PATH, "wb") as f:
            pickle.dump(self.label_encoder, f)
        with open(ENCODINGS_PATH, "wb") as f:
            pickle.dump({"encodings": self.known_encodings, "labels": self.known_labels}, f)
        logger.info("Model saved to disk.")

    def add_employee_photo(self, employee_id: str, image_bytes: bytes) -> dict:
        """Add a single employee photo for training."""
        try:
            image = face_recognition.load_image_file(BytesIO(image_bytes))
            face_locations = face_recognition.face_locations(image, model="hog")

            if len(face_locations) == 0:
                return {"success": False, "message": "No face detected in the image."}
            if len(face_locations) > 1:
                return {"success": False, "message": f"Multiple faces ({len(face_locations)}) detected. Please provide a photo with a single face."}

            encoding = face_recognition.face_encodings(image, face_locations)[0]

            # Save photo to disk
            employee_dir = os.path.join(TRAINING_DATA_DIR, employee_id)
            os.makedirs(employee_dir, exist_ok=True)
            photo_count = len(os.listdir(employee_dir))
            photo_path = os.path.join(employee_dir, f"{employee_id}_{photo_count + 1}.jpg")
            img = Image.open(BytesIO(image_bytes))
            img.save(photo_path)

            self.known_encodings.append(encoding)
            self.known_labels.append(employee_id)

            return {
                "success": True,
                "message": f"Photo added for employee '{employee_id}'.",
                "total_photos_for_employee": sum(1 for l in self.known_labels if l == employee_id),
                "photo_path": photo_path
            }
        except Exception as e:
            logger.error(f"Error adding employee photo: {e}")
            return {"success": False, "message": str(e)}

    def train(self) -> dict:
        """Train the classifier on all known face encodings."""
        if len(self.known_encodings) == 0:
            return {"success": False, "message": "No training data available. Add employee photos first."}

        unique_labels = set(self.known_labels)
        if len(unique_labels) < 2:
            return {
                "success": False,
                "message": f"Need at least 2 different employees to train. Currently have {len(unique_labels)}."
            }

        # Check minimum samples per class
        label_counts = {}
        for label in self.known_labels:
            label_counts[label] = label_counts.get(label, 0) + 1

        try:
            self.label_encoder = LabelEncoder()
            encoded_labels = self.label_encoder.fit_transform(self.known_labels)

            X = np.array(self.known_encodings)
            y = encoded_labels

            # Use SVM with probability calibration for confidence scores
            base_svm = SVC(kernel="rbf", gamma="scale", C=10.0)
            self.classifier = CalibratedClassifierCV(base_svm, cv=min(3, min(label_counts.values())))
            self.classifier.fit(X, y)

            self.is_trained = True
            self._save_model()

            return {
                "success": True,
                "message": "Model trained successfully.",
                "num_employees": len(unique_labels),
                "employees": list(unique_labels),
                "samples_per_employee": label_counts,
                "total_samples": len(self.known_encodings)
            }
        except Exception as e:
            logger.error(f"Training error: {e}")
            return {"success": False, "message": f"Training failed: {str(e)}"}

    def train_from_directory(self) -> dict:
        """Train model from employee_photos directory structure."""
        if not os.path.exists(TRAINING_DATA_DIR):
            return {"success": False, "message": f"Training directory '{TRAINING_DATA_DIR}' not found."}

        self.known_encodings = []
        self.known_labels = []
        skipped = []

        for employee_id in os.listdir(TRAINING_DATA_DIR):
            employee_dir = os.path.join(TRAINING_DATA_DIR, employee_id)
            if not os.path.isdir(employee_dir):
                continue

            for photo_file in os.listdir(employee_dir):
                photo_path = os.path.join(employee_dir, photo_file)
                if not photo_file.lower().endswith((".jpg", ".jpeg", ".png", ".bmp")):
                    continue

                try:
                    image = face_recognition.load_image_file(photo_path)
                    face_locations = face_recognition.face_locations(image, model="hog")

                    if len(face_locations) == 1:
                        encoding = face_recognition.face_encodings(image, face_locations)[0]
                        self.known_encodings.append(encoding)
                        self.known_labels.append(employee_id)
                    else:
                        skipped.append({
                            "file": photo_path,
                            "reason": f"Found {len(face_locations)} faces"
                        })
                except Exception as e:
                    skipped.append({"file": photo_path, "reason": str(e)})

        result = self.train()
        if skipped:
            result["skipped_photos"] = skipped
        return result

    def recognize(self, image_bytes: bytes, distance_threshold: float = 0.6) -> dict:
        """
        Recognize faces in an image and return detailed probability distributions.
        Returns confidence scores for ALL known employees.
        """
        if not self.is_trained:
            raise ValueError("Model is not trained. Please train the model first.")

        try:
            image = face_recognition.load_image_file(BytesIO(image_bytes))
            face_locations = face_recognition.face_locations(image, model="hog")

            if len(face_locations) == 0:
                return {
                    "success": True,
                    "faces_detected": 0,
                    "results": [],
                    "timestamp": datetime.now().isoformat(),
                    "message": "No faces detected in the image."
                }

            face_encodings = face_recognition.face_encodings(image, face_locations)

            results = []
            for idx, (encoding, location) in enumerate(zip(face_encodings, face_locations)):
                top, right, bottom, left = location

                # Get SVM probability distribution
                encoding_array = np.array(encoding).reshape(1, -1)
                probabilities = self.classifier.predict_proba(encoding_array)[0]

                # Build detailed probability distribution
                probability_distribution = {}
                for class_idx, class_name in enumerate(self.label_encoder.classes_):
                    probability_distribution[class_name] = round(float(probabilities[class_idx]), 6)

                # Sort by probability descending
                sorted_distribution = dict(
                    sorted(probability_distribution.items(), key=lambda x: x[1], reverse=True)
                )

                # Get best match
                best_match_idx = np.argmax(probabilities)
                best_match_label = self.label_encoder.classes_[best_match_idx]
                best_match_confidence = float(probabilities[best_match_idx])

                # Calculate face distances to all known encodings for the best match
                employee_encodings = [
                    enc for enc, lbl in zip(self.known_encodings, self.known_labels)
                    if lbl == best_match_label
                ]
                face_distances = face_recognition.face_distance(employee_encodings, encoding)
                min_distance = float(np.min(face_distances))
                avg_distance = float(np.mean(face_distances))

                # Determine if this is a known or unknown person
                is_known = min_distance <= distance_threshold and best_match_confidence > 0.3

                # Calculate distance-based scores for all employees
                distance_scores = {}
                for emp_id in set(self.known_labels):
                    emp_encodings = [
                        enc for enc, lbl in zip(self.known_encodings, self.known_labels)
                        if lbl == emp_id
                    ]
                    distances = face_recognition.face_distance(emp_encodings, encoding)
                    distance_scores[emp_id] = {
                        "min_distance": round(float(np.min(distances)), 6),
                        "avg_distance": round(float(np.mean(distances)), 6),
                        "max_distance": round(float(np.max(distances)), 6),
                        "num_reference_photos": len(emp_encodings)
                    }

                # Sort distance scores by min_distance
                sorted_distance_scores = dict(
                    sorted(distance_scores.items(), key=lambda x: x[1]["min_distance"])
                )

                face_result = {
                    "face_index": idx,
                    "bounding_box": {
                        "top": top,
                        "right": right,
                        "bottom": bottom,
                        "left": left
                    },
                    "identification": {
                        "predicted_employee": best_match_label if is_known else "UNKNOWN",
                        "is_recognized": is_known,
                        "confidence": round(best_match_confidence, 6),
                        "min_face_distance": round(min_distance, 6),
                        "avg_face_distance": round(avg_distance, 6),
                        "distance_threshold": distance_threshold,
                    },
                    "probability_distribution": sorted_distribution,
                    "distance_analysis": sorted_distance_scores,
                    "security_assessment": {
                        "access_recommendation": "GRANT" if is_known and best_match_confidence > 0.5 else "DENY",
                        "risk_level": _calculate_risk_level(best_match_confidence, min_distance, is_known),
                        "requires_manual_review": not is_known or best_match_confidence < 0.5
                    }
                }

                results.append(face_result)

            return {
                "success": True,
                "faces_detected": len(face_locations),
                "results": results,
                "timestamp": datetime.now().isoformat(),
                "model_info": {
                    "known_employees": list(self.label_encoder.classes_),
                    "total_training_samples": len(self.known_encodings),
                    "distance_threshold": distance_threshold
                }
            }

        except Exception as e:
            logger.error(f"Recognition error: {e}")
            raise


def _calculate_risk_level(confidence: float, distance: float, is_known: bool) -> str:
    """Calculate security risk level based on recognition metrics."""
    if not is_known:
        return "HIGH"
    if confidence > 0.8 and distance < 0.4:
        return "LOW"
    if confidence > 0.5 and distance < 0.5:
        return "MEDIUM"
    return "HIGH"


# Initialize model
model = FaceRecognitionModel()


