@app.post("/employees/{employee_id}/photos")
async def add_employee_photo(employee_id: str, file: UploadFile = File(...)):
    """Upload a photo for an employee to use in training."""
    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image.")

    image_bytes = await file.read()
    result = model.add_employee_photo(employee_id, image_bytes)

    if not result["success"]:
        raise HTTPException(status_code=400, detail=result["message"])

    return JSONResponse(status_code=201, content=result)


@app.post("/train")
async def train_model():
    """Train the facial recognition model on all uploaded employee photos."""
    result = model.train()
    if not result["success"]:
        raise HTTPException(status_code=400, detail=result["message"])
    return result


@app.post("/train/from-directory")
async def train_from_directory():
    """
    Train model from the employee_photos directory.
    Directory structure: employee_photos/<employee_id>/<photo_files>
    """
    result = model.train_from_directory()
    if not result["success"]:
        raise HTTPException(status_code=400, detail=result["message"])
    return result


@app.post("/recognize")
async def recognize_face(
    file: UploadFile = File(...),
    distance_threshold: float = 0.6
):
    """
    Recognize faces in an uploaded image.
    Returns detailed probability distribution over all known employees
    with confidence scores, face distances, and security assessments.
    """
    if not model.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model is not trained. Please train the model first using /train endpoint."
        )

    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image.")

    if not (0.0 < distance_threshold <= 1.0):
        raise HTTPException(status_code=400, detail="distance_threshold must be between 0 and 1.")

    image_bytes = await file.read()

    try:
        result = model.recognize(image_bytes, distance_threshold=distance_threshold)
        return result
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
    except Exception as e:
        logger.error(f"Recognition endpoint error: {e}")
        raise HTTPException(status_code=500, detail=f"Internal error during recognition: {str(e)}")


@app.get("/employees")
async def list_employees():
    """List all registered employees and their photo counts."""
    if not os.path.exists(TRAINING_DATA_DIR):
        return {"employees": [], "total": 0}

    employees = []
    for emp_id in os.listdir(TRAINING_DATA_DIR):
        emp_dir = os.path.join(TRAINING_DATA_DIR, emp_id)
        if os.path.isdir(emp_dir):
            photo_count = len([
                f for f in os.listdir(emp_dir)
                if f.lower().endswith((".jpg", ".jpeg", ".png", ".bmp"))
            ])
            training_samples = sum(1 for l in model.known_labels if l == emp_id)
            employees.append({
                "employee_id": emp_id,
                "photos_on_disk": photo_count,
                "training_samples_loaded": training_samples
            })

    return {"employees": employees, "total": len(employees)}


@app.delete("/employees/{employee_id}")
async def remove_employee(employee_id: str):
    """Remove an employee and their photos from the system."""
    employee_dir = os.path.join(TRAINING_DATA_DIR, employee_id)

    if os.path.exists(employee_dir):
        shutil.rmtree(employee_dir)

    # Remove from in-memory data
    indices_to_remove = [i for i, l in enumerate(model.known_labels) if l == employee_id]
    for idx in sorted(indices_to_remove, reverse=True):
        model.known_encodings.pop(idx)
        model.known_labels.pop(idx)

    if indices_to_remove:
        return {
            "success": True,
            "message": f"Employee '{employee_id}' removed. Re-train the model to update.",
            "removed_samples": len(indices_to_remove),
            "requires_retrain": True
        }
    else:
        raise HTTPException(status_code=404, detail=f"Employee '{employee_id}' not found.")


@app.get("/model/info")
async def model_info():
    """Get detailed information about the current model."""
    if not model.is_trained:
        return {
            "trained": False,
            "message": "Model is not trained.",
            "pending_samples": len(model.known_encodings)
        }

    label_counts = {}
    for label in model.known_labels:
        label_counts[label] = label_counts.get(label, 0) + 1

    return {
        "trained": True,
        "known_employees": list(model.label_encoder.classes_),
        "num_employees": len(model.label_encoder.classes_),
        "total_training_samples": len(model.known_encodings),
        "samples_per_employee": label_counts,
        "model_type": "CalibratedSVC (RBF kernel)",
        "model_files": {
            "classifier": MODEL_PATH,
            "encoder": ENCODER_PATH,
            "encodings": ENCODINGS_PATH
        }
    }


